import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import axios from 'axios';

const HomePage = () => {
  const [collections, setCollections] = useState([]);
  const [latestProducts, setLatestProducts] = useState([]);
  const [activeSlide, setActiveSlide] = useState(0);
  const [showQuickView, setShowQuickView] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [featuredProduct, setFeaturedProduct] = useState(null);
  const [featuredCollection, setFeaturedCollection] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [collectionsRes, productsRes, featuredProductRes] = await Promise.all([
          axios.get('http://localhost:3000/api/v1/collections'),
          axios.get('http://localhost:3000/api/v1/products/latest'),
          axios.get('http://localhost:3000/api/v1/products/featured')
        ]);
        setCollections(collectionsRes.data);
        setLatestProducts(productsRes.data);
        setFeaturedProduct(featuredProductRes.data);
        if (collectionsRes.data.length > 0) {
          setFeaturedCollection(collectionsRes.data[0]);
        }
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="bg-black text-white min-h-screen">
      {/* Hero Section with Parallax */}
      <section className="relative h-screen overflow-hidden">
        <motion.div
          initial={{ scale: 1.2 }}
          animate={{ scale: 1 }}
          transition={{ duration: 20, repeat: Infinity }}
          className="absolute inset-0"
          style={{ 
            background: `url(${featuredProduct?.image}) no-repeat center center`,
            backgroundSize: 'cover',
            filter: 'brightness(0.5)'
          }}
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/50 via-transparent to-black" />
        <div className="relative container mx-auto px-4 h-full flex items-center">
          <div className="max-w-2xl">
            <motion.h1 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-6xl font-bold mb-6"
            >
              Collect the Extraordinary
            </motion.h1>
            <p className="text-xl text-gray-300 mb-8">
              Discover our premium collection of die-cast models, where passion meets precision.
            </p>
            <Link to="/collections" className="inline-block bg-red-500 hover:bg-red-600 text-white px-8 py-4 rounded-full transition-colors">
              Explore Collections
            </Link>
          </div>
        </div>
      </section>

      {/* Featured Collections */}
      <section className="py-20 bg-zinc-950">
        <div className="container mx-auto px-4">
          <h2 className="text-4xl font-bold mb-12 text-center">Featured Collections</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {collections.slice(0, 3).map((collection) => (
              <motion.div
                key={collection._id}
                whileHover={{ y: -10 }}
                className="group relative rounded-2xl overflow-hidden"
              >
                <div className="aspect-[4/5] bg-zinc-900">
                  <img 
                    src={collection.image} 
                    alt={collection.name}
                    className="w-full h-full object-cover transition-transform group-hover:scale-110"
                  />
                </div>
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
                  <div className="absolute bottom-0 p-6">
                    <h3 className="text-2xl font-bold mb-2">{collection.name}</h3>
                    <p className="text-gray-300 mb-4">{collection.description}</p>
                    <Link to={`/collections/${collection._id}`} className="inline-block bg-white/10 hover:bg-white/20 backdrop-blur-sm px-6 py-3 rounded-full transition-colors">
                      View Collection
                    </Link>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Latest Products Carousel */}
      <section className="py-20">
        <div className="container mx-auto px-4">
          <h2 className="text-4xl font-bold mb-12 text-center">Latest Arrivals</h2>
          <div className="relative">
            <div className="overflow-hidden">
              <motion.div
                animate={{ x: `-${activeSlide * 100}%` }}
                transition={{ type: "spring", stiffness: 300, damping: 30 }}
                className="flex"
              >
                {latestProducts.map((product) => (
                  <div key={product._id} className="min-w-full md:min-w-[33.333%] px-4">
                    <div className="bg-zinc-900 rounded-2xl overflow-hidden">
                      <div className="aspect-square relative group">
                        <img 
                          src={product.image} 
                          alt={product.name}
                          className="w-full h-full object-cover"
                        />
                        <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <button
                            onClick={() => {
                              setSelectedProduct(product);
                              setShowQuickView(true);
                            }}
                            className="bg-white text-black px-6 py-3 rounded-full hover:bg-gray-100 transition-colors"
                          >
                            Quick View
                          </button>
                        </div>
                      </div>
                      <div className="p-6">
                        <h3 className="text-xl font-bold mb-2">{product.name}</h3>
                        <p className="text-gray-400 mb-4">${product.price}</p>
                        <button className="w-full bg-red-500 hover:bg-red-600 py-3 rounded-full transition-colors">
                          Add to Cart
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </motion.div>
            </div>
            <button
              onClick={() => setActiveSlide(Math.max(0, activeSlide - 1))}
              className="absolute left-4 top-1/2 -translate-y-1/2 w-12 h-12 rounded-full bg-black/50 hover:bg-black/75 flex items-center justify-center backdrop-blur-sm transition-colors"
            >
              <i className="fa-solid fa-chevron-left"></i>
            </button>
            <button
              onClick={() => setActiveSlide(Math.min(latestProducts.length - 1, activeSlide + 1))}
              className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 rounded-full bg-black/50 hover:bg-black/75 flex items-center justify-center backdrop-blur-sm transition-colors"
            >
              <i className="fa-solid fa-chevron-right"></i>
            </button>
          </div>
        </div>
      </section>

      {/* Brand Story */}
      <section className="py-20 bg-zinc-950">
        <div className="container mx-auto px-4">
          <div className="grid md:grid-cols-2 gap-12 items-center">
            <div>
              <h2 className="text-4xl font-bold mb-6">Our Story</h2>
              <p className="text-gray-400 mb-8">
                Since 1995, we've been curating the finest die-cast models for collectors worldwide. 
                Our passion for detail and commitment to quality has made us the leading destination 
                for premium collectible cars.
              </p>
              <Link to="/about" className="inline-block border border-white/20 hover:border-white/40 px-8 py-4 rounded-full transition-colors">
                Learn More
              </Link>
            </div>
            <div className="relative aspect-square rounded-2xl overflow-hidden">
              <img 
                src={featuredCollection?.image}
                alt="Featured Collection"
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent" />
            </div>
          </div>
        </div>
      </section>

      {/* Newsletter */}
      <section className="py-20 bg-gradient-to-b from-zinc-950 to-black">
        <div className="container mx-auto px-4 text-center">
          <h2 className="text-4xl font-bold mb-6">Stay Updated</h2>
          <p className="text-gray-400 mb-8 max-w-2xl mx-auto">
            Subscribe to our newsletter to receive updates about new releases, 
            exclusive offers, and collecting tips.
          </p>
          <form className="max-w-md mx-auto flex gap-4">
            <input
              type="email"
              placeholder="Enter your email"
              className="flex-1 bg-white/10 rounded-full px-6 py-4 outline-none focus:ring-2 focus:ring-red-500"
            />
            <button type="submit" className="bg-red-500 hover:bg-red-600 px-8 py-4 rounded-full transition-colors">
              Subscribe
            </button>
          </form>
        </div>
      </section>

      {/* Quick View Modal */}
      {showQuickView && selectedProduct && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50">
          <div className="bg-zinc-900 rounded-2xl max-w-4xl w-full mx-4 overflow-hidden">
            <div className="grid md:grid-cols-2">
              <div className="aspect-square">
                <img 
                  src={selectedProduct.image} 
                  alt={selectedProduct.name}
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="p-8">
                <div className="flex justify-between items-start mb-6">
                  <h3 className="text-2xl font-bold">{selectedProduct.name}</h3>
                  <button 
                    onClick={() => setShowQuickView(false)}
                    className="w-8 h-8 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center"
                  >
                    <i className="fa-solid fa-times"></i>
                  </button>
                </div>
                <p className="text-gray-400 mb-6">{selectedProduct.description}</p>
                <p className="text-2xl font-bold mb-8">${selectedProduct.price}</p>
                <button className="w-full bg-red-500 hover:bg-red-600 py-4 rounded-full transition-colors mb-4">
                  Add to Cart
                </button>
                <Link 
                  to={`/products/${selectedProduct._id}`}
                  className="block text-center border border-white/20 hover:border-white/40 py-4 rounded-full transition-colors"
                >
                  View Full Details
                </Link>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default HomePage;
